    date: "06 February, 2025",
    image: "/images/news3.jpg",
    description: "How is open source regulated in copyright law in Indonesia? Despite its nature...",
    fullText: "Full article content goes here. This is the detailed explanation..."
  },
];

function App() {
  return (
    <Router>
      <Navbar />
      <Routes>
        {/* Static Routes */}
        <Route
          path="/"
          element={
            <>
              <section id="HOME">
                <Home />
              </section>
              <section id="ABOUT US">
                <About />
              </section>
              <section id="AREAS OF PRACTICE">
                <PracticeAreas />
              </section>
              <section id="OUR PROFESSIONALS">
                <Professionals />
              </section>
              <section id="NEWS & ARTICLES">
                <News articles={articles} />
              </section>
              <section id="GALLERY">
                <Gallery />
              </section>
              <section id="CONTACT US">
                <Contact />
              </section>
            </>
          }
        />
        
        <Route path="/news" element={<News articles={articles} />} />
        <Route path="/more-news" element={<AllNews articles={articles} />} />
      </Routes>
    </Router>
  );
}

export default App;
